-- ============================================================================
--  ACTUALIZACIÓN DE EQUIPOS — reemplaza el listado simple por el registro real
--  de activos (443 Manantiales + 827 Olas). Ejecutar completo en SQL Editor.
-- ============================================================================
begin;

-- 1. Columnas nuevas para aprovechar el detalle del registro de activos
alter table equipos add column if not exists estado text;
alter table equipos add column if not exists area text;
alter table equipos add column if not exists criticidad text;

-- 2. Seguridad: si alguna línea de costo ya apuntaba a un equipo del listado
--    anterior, se desvincula (queda sin equipo asignado) en vez de romperse.
update costos_mantenimiento set equipo_id = null where equipo_id is not null;

-- 3. Se reemplaza el listado completo por el registro de activos real
--    (DELETE en vez de TRUNCATE: Postgres no permite truncar una tabla
--    referenciada por llave foránea, aunque ya esté desvinculada)
delete from equipos;

-- 4. Carga de los 1.270 activos reales (443 Manantiales + 827 Olas)

-- MANANTIALES: 443 activos

-- OLAS: 827 activos

commit;
